-    else result[arg.slice(2)] = true
+  let j = 0
+  while (j < argv.length) {
+    const arg = argv[j]
+    if (arg === '-') {
+      result._.push(arg)
+      j++
+      continue
+    }
+    if (!arg.startsWith('--')) {
+      result._.push(arg)
+      j++
+      continue
+    }
+    if (arg.indexOf('=') !== -1) {
+      const key = arg.slice(2, arg.indexOf('='))
+      result[key] = arg.slice(arg.indexOf('=') + 1)
+      j++
+      continue
+    }
+    if (j + 1 < argv.length && !argv[j + 1].startsWith('-')) {
+      result[arg.slice(2)] = argv[++j]
+      j++
+      continue
+    }
+    result[arg.slice(2)] = true
+    j++
   }
   return result
 }

